import{_ as e,c as a,o as r,a as i}from"./app.c27b58b7.js";const o="/scrum/assets/sprint-backlog1.f1f85011.jpg",l="/scrum/assets/sprint-backlog2.03b018ad.jpg",s="/scrum/assets/sprint-backlog3.2bd14300.jpg",t="/scrum/assets/sprint-backlog4.7f065d88.jpg",_=JSON.parse('{"title":"Pila del Sprint","description":"","frontmatter":{},"headers":[{"level":2,"title":"Dividiendo Historias de Usuario en tareas","slug":"dividiendo-historias-de-usuario-en-tareas","link":"#dividiendo-historias-de-usuario-en-tareas","children":[]},{"level":2,"title":"Otro detalle a considerar, es el tiempo que demanda cada tarea.","slug":"otro-detalle-a-considerar-es-el-tiempo-que-demanda-cada-tarea","link":"#otro-detalle-a-considerar-es-el-tiempo-que-demanda-cada-tarea","children":[]},{"level":2,"title":"Condiciones","slug":"condiciones","link":"#condiciones","children":[]},{"level":2,"title":"Formato y soporte","slug":"formato-y-soporte","link":"#formato-y-soporte","children":[]}],"relativePath":"artifacts/sprint-backlog.md"}'),n={name:"artifacts/sprint-backlog.md"},d=i('<h1 id="pila-del-sprint" tabindex="-1">Pila del Sprint <a class="header-anchor" href="#pila-del-sprint" aria-hidden="true">#</a></h1><blockquote><p>La Pila del Sprint es una lista reducida de \xEDtems de la Pila del Producto, que han sido negociados entre el Due\xF1o del Producto y el Equipo de Desarrollo durante la planificaci\xF3n del Sprint. Esta lista, se genera al comienzo de cada Sprint y representa aquellas caracter\xEDsticas que el equipo se compromete a desarrollar durante la iteraci\xF3n actual.</p></blockquote><p>La Pila del Sprint es la lista que descompone las funcionalidades de la Pila del Producto (Historias de Usuario) en las tareas necesarias para construir un incremento: una parte completa y operativa del producto. La realiza el equipo durante la reuni\xF3n de planificaci\xF3n del Sprint, auto-asignando cada tarea a un miembro del equipo, e indicando en la misma lista cu\xE1nto esfuerzo se prev\xE9 que falta para terminarla.</p><p>La Pila del Sprint descompone el trabajo en unidades de tama\xF1o adecuado para monitorizar el avance a diario, e identificar riesgos y problemas sin necesidad de procesos de gesti\xF3n complejos. Los \xEDtems incluidos en la Pila del Sprint se dividen en tareas las cuales generalmente, no demanden una duraci\xF3n superior a un d\xEDa de trabajo del miembro del equipo que se haya asignado dicha tarea. Se actualiza diariamente por el equipo y de manera permanente, muestra:</p><ul><li>Las tareas pendientes, en curso y terminadas.</li><li>La estimaci\xF3n del esfuerzo pendiente de cada tarea sin concluir.</li><li>El nombre del miembro del equipo que se ha asignado dicha tarea.</li></ul><p>Generalmente, la Pila del Sprint, se visualiza mediante un tablero f\xEDsico, montado en alguna de las paredes de la sala de desarrollo.</p><p><img src="'+o+'" alt="sprint-backlog"></p><p>Es muy frecuente, a la vez de ser una pr\xE1ctica recomendada, que cada tarea sea a la vez <em>&quot;etiquetada&quot;</em>, diferenciando por ejemplo cuando representa una correcci\xF3n de error, una tarea de dise\xF1o, una prueba, etc.</p><p><img src="'+l+'" alt="sprint-backlog"></p><h2 id="dividiendo-historias-de-usuario-en-tareas" tabindex="-1">Dividiendo Historias de Usuario en tareas <a class="header-anchor" href="#dividiendo-historias-de-usuario-en-tareas" aria-hidden="true">#</a></h2><p>La estrategia consiste en desmembrar el item a la m\xEDnima expresi\xF3n posible, encuadrada en un mismo tipo de actividad. El desmembramiento debe hacerse <em>&quot;de lo general a lo particular, y de lo particular al detalle&quot;</em>.</p><p><img src="'+s+'" alt="sprint-backlog"></p><p><strong>An\xE1lisis General</strong>: Es aquel que responde a la pregunta <em>\xBFqu\xE9 es?</em></p><p><strong>Por ejemplo</strong>: Un sistema de validaci\xF3n de usuarios registrados</p><p><strong>An\xE1lisis Particular</strong>: Es el que responde a la pregunta <em>\xBFc\xF3mo hacerlo?</em></p><p><strong>Por ejemplo</strong>: Arquitectura MVC (requiere hacer el modelo, la l\xF3gica y la GUI de la vista y el controlador).</p><p><strong>An\xE1lisis Detallado</strong>: Es el que responde a la pregunta general <em>\xBFqu\xE9 tareas se necesitan hacer para lograrlo?</em> Los detalles, son aquellas restricciones que deber\xE1n considerarse para todo lo anterior.</p><p><strong>Por ejemplo</strong>: La creaci\xF3n del modelo, repercutir\xE1 en la base de datos. Por lo cual, tras crear los nuevos modelos, habr\xE1 que correr el ORM para que modifique las tablas.</p><h2 id="otro-detalle-a-considerar-es-el-tiempo-que-demanda-cada-tarea" tabindex="-1">Otro detalle a considerar, es el tiempo que demanda cada tarea. <a class="header-anchor" href="#otro-detalle-a-considerar-es-el-tiempo-que-demanda-cada-tarea" aria-hidden="true">#</a></h2><p><strong>Por ejemplo</strong>: Correr un ORM lleva solo algunos minutos, pues no puede ser considerado una \xFAnica tarea. Entonces, puede <em>&quot;sumarse como detalle&quot;</em> a la tarea <em>&quot;crear modelos&quot;</em>. De manera contraria, documentar en el manual del usuario, llevar\xE1 todo un d\xEDa de trabajo. Por lo cual, debe asignarse a una \xFAnica tarea.</p><p><strong>Entonces se debe</strong>:</p><ul><li><p>Crear el modelo Usuario y correr el ORM para modificar las tablas</p><ul><li>Etiqueta: programaci\xF3n</li><li>Esfuerzo: 2 h</li></ul></li><li><p>Dise\xF1ar un formulario HTML para insertar usuario y contrase\xF1a</p><ul><li>Etiqueta: dise\xF1o</li><li>Esfuerzo: 4 h</li></ul></li><li><p>Desarrollar la l\xF3gica de la vista del formulario para el logueo</p><ul><li>Etiqueta: programaci\xF3n</li><li>Esfuerzo: 4 h</li></ul></li><li><p>Crear el controlador para el modelo</p><ul><li>Etiqueta: programaci\xF3n</li><li>Esfuerzo: 6 h</li></ul></li><li><p>Correr las pruebas e integrar</p><ul><li>Etiqueta: prueba</li><li>Esfuerzo: 1 h</li></ul></li></ul><p>Finalmente, dichas tareas se plasmar\xE1n en diferentes fichas (una tarea en cada uno). Los miembros del equipo decidir\xE1n qu\xE9 tareas se asignar\xE1 cada uno y se colocar\xE1n las fichas en el tablero:</p><p><img src="'+t+'" alt="sprint-backlog"></p><p>Es tambi\xE9n una herramienta para la comunicaci\xF3n visual directa del equipo.</p><h2 id="condiciones" tabindex="-1">Condiciones <a class="header-anchor" href="#condiciones" aria-hidden="true">#</a></h2><ul><li>S\xF3lo el equipo la puede modificar durante el Sprint.</li><li>Es realizada de forma conjunta por todos los miembros del equipo.</li><li>Cubre todas las tareas identificadas por el equipo para conseguir el objetivo del Sprint.</li><li>Es visible para todo el equipo. Idealmente en un tablero o pared en el mismo espacio f\xEDsico donde trabaja el equipo.</li><li>Las tareas demasiado grandes deben descomponerse en otras m\xE1s peque\xF1as. Se deben considerar \u201Cgrandes\u201D las tareas que necesitan m\xE1s de un d\xEDa para realizarse.</li></ul><h2 id="formato-y-soporte" tabindex="-1">Formato y soporte <a class="header-anchor" href="#formato-y-soporte" aria-hidden="true">#</a></h2><p>Son soportes habituales:</p><ul><li>Tablero f\xEDsico o pared.</li><li>Hoja de c\xE1lculo.</li><li>Herramienta colaborativa o de gesti\xF3n de proyectos.</li></ul><p>Y sobre el m\xE1s adecuado a las caracter\xEDsticas del proyecto, oficina y equipo, lo apropiado es dise\xF1ar el formato m\xE1s c\xF3modo para todos, teniendo en cuenta los siguientes criterios:</p><ul><li>Incluir s\xF3lo la informaci\xF3n estrictamente necesaria.</li><li>Facilitar la consulta y la comunicaci\xF3n diaria y directa del equipo.</li><li>Debe servir de medio para registrar en cada reuni\xF3n de Apertura Diaria del Sprint, el tiempo que le <em>\u201Cdeber\xEDa\u201D</em> quedar a cada tarea.</li><li>Incluir la siguiente informaci\xF3n: Pila del Sprint, persona responsable de cada tarea, estado en el que se encuentra y tiempo de trabajo que queda para completarla.</li></ul><blockquote><p>Durante el Sprint, el equipo actualiza a diario en ella los <em>\u201Ctiempos pendientes\u201D</em> de cada tarea. Al mismo tiempo, con estos datos traza en el Gr\xE1fico de Avance el trabajo consumido.</p></blockquote>',33),c=[d];function u(p,m,g,q,b,h){return r(),a("div",null,c)}const v=e(n,[["render",u]]);export{_ as __pageData,v as default};
